import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './Auth.css';

export default function Login() {
  const [loginType, setLoginType] = useState('student');
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [serverStatus, setServerStatus] = useState('checking');
  const navigate = useNavigate();

  useEffect(() => {
    checkServer();
    const interval = setInterval(checkServer, 30000);
    return () => clearInterval(interval);
  }, []);

  const checkServer = async () => {
    try {
      await axios.get('http://localhost:5000/api/health');
      setServerStatus('online');
    } catch {
      setServerStatus('offline');
    }
  };

  const handleChange = e => setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleSubmit = async e => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const res = await axios.post('http://localhost:5000/api/auth/login', formData);
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('user', JSON.stringify(res.data.user));
      navigate(res.data.user.role === 'admin' ? '/admin' : '/student');
    } catch {
      setError('Invalid email or password');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-wrapper">
      <div className="auth-card">
        <div className="auth-header">
          <h1>Hostel<span>Hub</span></h1>
          <p>Complaint Management</p>
          <div className={`server-status ${serverStatus}`}>
            {serverStatus === 'online' ? '🟢 Server Connected' : '🔴 Server Disconnected'}
          </div>
        </div>
        <div className="login-tabs">
          <button className={`tab ${loginType === 'student' ? 'active' : ''}`} onClick={() => setLoginType('student')}>👨‍🎓 Student</button>
          <button className={`tab ${loginType === 'admin' ? 'active' : ''}`} onClick={() => setLoginType('admin')}>👨‍💼 Admin</button>
        </div>
        <div className="auth-form">
          {error && <div className="error-message">{error}</div>}
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Email</label>
              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                placeholder={loginType === 'admin' ? 'admin@hostelhub.com' : 'your@email.com'}
                required
              />
            </div>
            <div className="form-group">
              <label>Password</label>
              <input
                type="password"
                name="password"
                value={formData.password}
                onChange={handleChange}
                placeholder="Enter your password"
                required
              />
            </div>
            <button type="submit" className="btn-login" disabled={loading || serverStatus === 'offline'}>
              {loading ? 'Logging in...' : 'Login'}
            </button>
          </form>
          <div className="info-box" style={{ marginTop: '20px' }}>
            New here? <a href="/register">Register as student</a>
          </div>
          {loginType === 'admin' && (
            <div style={{ marginTop: '10px', fontSize: '13px', color: '#666' }}>
              Default admin: admin@hostelhub.com / admin123
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
